import '../../Stylesheets/LandingPage/Card.css'

export default function Card() {
    const texto = () =>{
        var texto1 = props.texto
        var verde = props.verde
        var texto2 = props.texto2
        return <h1>{texto1} <span>{verde}</span> {texto2}</h1>
      }
    
      const btnVazado = () => {
        if (props.botao === "vazado") {
          return <button type="button" className="btn vazado">Desafio Semanal</button>
        } else {
          return <button type="button" className="btn">Desafio Semanal</button>
        }
      }
    
      return (
        <div className="content">
          {texto()}
          <p>{props.textoPqn}</p>
          {btnVazado()}
        </div>
  )
}
